var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"꺄아악! 방금 봤지?! 쥐가 내 팔뚝보다 커!","JPN":"きゃーっ！　今のみた！？　アタシの腕よりおっきいネズミ！","ENG":"Aaaah! Did you just see that?! That rat's bigger than my arm!","TWN":"啊～～！你有看到嗎？那隻老鼠比我的手臂還大！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여긴 대정화 전쟁 이후 폐쇄된 지하철도입니다, 휴먼.","JPN":"ここは大浄化戦争以降、閉鎖された地下鉄です、ヒューマン。","ENG":"This underground railway has been closed down since the Grand Purification War, human.","TWN":"人類，這裡是淨化之戰後荒廢的地鐵。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"팔뚝만큼 커다란 쥐나 손바닥만 한 바퀴벌레가 있어도 이상할 것 없죠.","JPN":"腕ほどの大きさのネズミや、手のひらサイズのゴキブリがいてもおかしくありません。","ENG":"Giant rats and cockroaches are hardly an anomaly in this place.","TWN":"有跟手臂一樣大的老鼠，或是跟手掌一樣大的蟑螂，完全不足為奇。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……그 바퀴벌레, 혹시 날아다니기도 할까?","JPN":"……そのゴキブリ、飛んだりする？","ENG":"Those roaches don't fly… do they?","TWN":"……那蟑螂…會飛嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"마침 저기 한 마리 있군요. 확인해 보시겠습니까.","JPN":"ちょうどあそこに1匹いますね。確かめてみますか？","ENG":"I see one right there. Would you like to find out?","TWN":"那裡剛好有隻蟑螂，要確認看看嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"또 언니 놀리지, 너? 자꾸 그러면 여기다 버리고 간다?","JPN":"もう！　またお姉ちゃんをからかって！　そんなことしたらここに置いていくよ？","ENG":"Stop messing with me! Or I'll leave you here all by yourself!","TWN":"你是不是又在鬧我！再這樣我要把你扔在這裡喔！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들은 참 제멋대로군요. 협박해서 끌고 나올 때는 언제고.","JPN":"ヒューマンというのは実に身勝手ですね。脅迫して無理やり連れてきたのに置いていくとは。","ENG":"You humans are such fickle creatures. Just moments ago, you threatened to tie me up if I didn't join you.","TWN":"人類真是任性，明明剛才是你硬把我帶到這裡的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"애초에 어떤 근거로 엠마가 여기에 있다고 확신하는 겁니까.","JPN":"そもそも、どういった根拠でここにエマがいると確信しているのですか？","ENG":"On what basis are you so certain that Emma is here?","TWN":"請問你確定愛瑪就在這裡的根據是什麼？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"별로 확신해서 온 건 아냐. 여기에도 없으면 찾기 글렀다는 거지.","JPN":"別に確信したからここに来たわけじゃないよ。\\nただ、ここにもいなかったらこれ以上の捜索はもう無理ってことになるだけ……","ENG":"I'm not certain about anything, really. I'm just saying if she's not here either… it's hopeless.","TWN":"我不是因為確定才來的，是因為這裡也沒有的話，可能有點不妙。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이 근방 갱단들 대부분이 원장님한테 신세진 적 있다는 얘기는 저번에 해 줬지?","JPN":"この辺のギャングのほとんどが院長にお世話になったことがあるって話はこの前したよね？","ENG":"Did I tell you how most gangs around here owe the headmaster a favor?","TWN":"我上次有跟你說過吧？這附近的幫派大部分都欠院長人情。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그렇지만 맛이 간 약쟁이나 연고 없는 범죄자들은 그런 사정 신경 안 쓰거든.","JPN":"でもラリったジャンキーや縁故のない犯罪者たちは、そんなこと気にしないんだ。","ENG":"But junkies and petty criminals off on their own don't give a crap about that sort of thing.","TWN":"不過還是有些六親不認的毒蟲，或是白目的罪犯，沒在管什麼人情世故的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"엠마란 아이가 인신매매나 살인 같은 강력범죄의 표적이 됐을지도 모른다는 말이군요. 이해했습니다.","JPN":"エマという子が人身売買もしくは殺人といった凶悪犯罪の標的になったかもしれないということですね。理解しました。","ENG":"You mean Emma may be a target of human trafficking or other felonies such as murder. Duly noted.","TWN":"明白，意思是愛瑪可能會成為人口販子，或是壞人的目標對吧。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 이 앞은 지반이 부실하니 옆으로 붙어서 가죠.","JPN":"そしてこの先は地盤が緩くなっているので、壁に沿って進みましょう。","ENG":"Let us stay close to the walls as the ground here is prone to sinking.","TWN":"另外，前面的路危險，必須靠著旁邊走。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"얘가 잘 말하다 갑자기 뭐래. 금 하나 안 가 있는데.","JPN":"急にどういうこと？　ひび一本すら見えないよ？","ENG":"Uh… Okay? That's pretty random. I don't even see any cracks on the ground.","TWN":"話說到一半怎麼突然提到這個？路明明就好好的，也沒裂開？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러면 당신의 이해를 돕기 위해 이 콘크리트 파편을 던져 보겠습니다.","JPN":"それでは、あなたの理解を助けるためにこのコンクリートの破片を投げてみます。","ENG":"Then allow me to throw this piece of concrete to facilitate your understanding.","TWN":"我現在要丟這個混凝土碎片，幫助你釐清現況。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"무, 무너졌잖아……?","JPN":"く、崩れちゃった……？","ENG":"I-it just crumbled down!","TWN":"塌…塌咧……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};